// Store holds arbitrary values.
type Store struct {
	mu   sync.RWMutex
	data map[string]any
}

// Set stores value under key.
func (s *Store) Set(ctx context.Context, key string, value any) error {
	if err := ctx.Err(); err != nil {
		return fmt.Errorf("Store.Set: %w", err)
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.data[key] = value
	return nil
}
